mapper.insert:

    INSERT INTO CMN_FILE_DNLD_MGMT_MST /**cmn.filedown.insertCmnFileDnldMgmtMst */ 
	(
		     MENU_ID
		   , FILE_DN_DT
		   , USR_ID
		   , FILE_NM
		   , IP_INFO
		   , DUTY_NM
		   , FILE_ROUT
		   , FILE_SIZE
		   , DWNLD_RSN
		   , DATA_CNT
		   , EXCL_DNLD_ID
	) 
	VALUES 
	( 
		  nvl(#{menuId},'*')
		 ,sysdate
		 ,#{SESSION_USER_ID }
		 ,#{FILE_NM  }
		 ,#{IP_INFO  }
		 ,#{DUTY_NM  }
		 ,#{FILE_ROUT  }
		 ,#{FILE_SIZE  }
		 ,#{DWNLD_RSN }
		 ,#{DATA_CNT  }
		 ,#{EXCL_DNLD_ID }
	)

    INSERT INTO CMN_EXCL_DNLD_HST /**cmn.filedown.insertCmnExclDnldHst */ 
	(
		EXCL_DNLD_ID
		, MENU_ID
		, USR_ID
		, USR_NM
		, ORGN_ID
		, DUTY_NM
		, MENU_NM
		, EXCL_STRT_DT
		, SEARCH_VAL
	) 
	VALUES 
	(
		 #{EXCL_DNLD_ID}
		 ,NVL(#{MENU_ID},'*')
		 ,#{USR_ID}
		 ,#{USR_NM}
		 ,#{ORGN_ID}
		 ,#{DUTY_NM}
		 ,#{MENU_NM}
		 ,SYSDATE
		 ,#{SEARCH_VAL}
	)

mapper.select:
/* cmn.filedown.selectExcelList */ SELECT TO_CHAR(A.EXCL_STRT_DT, 'YYYY-MM-DD HH24:MI:SS') REGST_DTTM , A.MENU_NM , DECODE(C.EXEC_YN, 'N', '대기중', 'Y', FN_GET_CODENM('CMN0027',D.STAT_CD)) STAT_NM , B.FILE_ROUT FILE_ROUT , SUBSTR(B.FILE_ROUT,INSTR(B.FILE_ROUT,'/',-1)+1,lengthB(B.FILE_ROUT)) AS FILE_NM , A.USR_ID REGST_ID , A.USR_NM USR_NM , B.DWNLD_RSN DWNLD_RSN , A.EXCL_DNLD_ID FROM CMN_EXCL_DNLD_HST A , CMN_FILE_DNLD_MGMT_MST B , CMN_BATCH_REQUEST C , CMN_BATCH_EXEC_HST D WHERE A.EXCL_DNLD_ID = B.EXCL_DNLD_ID(+) AND A.EXCL_DNLD_ID = C.EXCL_DNLD_ID AND C.BATCH_REQ_ID = D.BATCH_REQ_ID(+) AND A.USR_ID = #{loginId}
AND #{searchStartDt} = TO_CHAR(A.EXCL_STRT_DT, 'YYYYMMDD')
ORDER BY A.EXCL_STRT_DT DESC

mapper.insert:
    INSERT INTO CMN_EXCL_DNLD_HST /**cmn.filedown.insertCmnExclDnldHstVO */ 
	(
		EXCL_DNLD_ID
		, MENU_ID
		, USR_ID
		, USR_NM
		, ORGN_ID
		, DUTY_NM
		, MENU_NM
		, EXCL_STRT_DT
		, SEARCH_VAL
	) 
	VALUES 
	(
		 #{exclDnldId}
		 ,#{menuId}
		 ,#{sessionUserId}
		 ,#{sessionUserName}
		 ,#{sessionUserOrgnId}
		 ,#{dutyNm}
		 ,#{menuNm}
		 ,SYSDATE
		 ,#{searchVal}
	)
